function si(l: list<integer>): integer { var s = 0; for (v in l) s += v; return s; }
function st(l: list<text>): text { var s = ''; for (v in l) s += v; return s; }
function tl(t: (list<integer>, list<text>)): text = si(t[0]) + st(t[1]);
entity city { name; country: text; }
entity user { name; score: integer; }
entity data { i: integer; d: decimal; t: text; ba: byte_array; u: user; c: city; }

